SELECT created_by, COUNT(form_id) AS form_count
  FROM forms
  GROUP BY created_by;

SELECT COUNT(error_id) AS error_count
FROM form_errors
WHERE form_id = 1 AND DATE(occurred_at) = '2023-01-02';

SELECT COUNT(submission_id) AS submission_count
FROM form_submissions
WHERE form_id = 1;

SELECT name
FROM forms
ORDER BY name;
